1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	type Item = { type: string; cursed?: boolean; enchantment?: number };
19	
20	function itemBasePremium(item: Item): number {
21	  const base = BASE_PREMIUMS[item.type];
22	  let premium = base;
23	  if (item.cursed) premium += base * CURSE_SURCHARGE_RATE;
24	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
25	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
26	  }
27	  return premium;
28	}
29	
30	function sumIndividualBasePremiums(items: Item[]): number {
31	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
32	}
33	
34	function groupByType(items: Item[]): Record<string, Item[]> {
35	  const groups: Record<string, Item[]> = {};
36	  for (const item of items) {
37	    if (!groups[item.type]) groups[item.type] = [];
38	    groups[item.type].push(item);
39	  }
40	  return groups;
41	}
42	
43	function premiumForGroup(groupItems: Item[]): number {
44	  return groupItems.length === BLOCK_SIZE
45	    ? BLOCK_OF_THREE_PREMIUM
46	    : sumIndividualBasePremiums(groupItems);
47	}
48	
49	function calculateBasePremium(items: Item[]): number {
50	  const groups = groupByType(items);
51	  return Object.values(groups).reduce((total, group) => total + premiumForGroup(group), 0);
52	}
53	
54	export function quote({ items }: { items: Item[]; years: number; priorContract: boolean }): { premium: number } {
55	  const basePremium = calculateBasePremium(items);
56	  const firstInsuranceSurcharges = items.length * FIRST_INSURANCE_SURCHARGE;
57	  return { premium: basePremium + firstInsuranceSurcharges + PROCESSING_FEE };
58	}
